// ── Node 3: 누수 피처 드롭 + 타입 정규화 + PK 검증 ────────────────────────────
// Baseball Savant CSV → 정제된 row items (one item per row)
const csvText = $input.first().json.data ?? '';
if (!csvText.trim()) {
  return [{ json: { error: 'CSV 데이터 없음', rows_processed: 0 } }];
}

// ① 누수 피처 전체 목록 (직접 누수 24 + 결과 누수 22 + 검토 추가 5 = 51개)
const LEAKAGE = new Set([
  // 직접 누수 — 릴리스 운동학
  'release_speed','release_spin_rate','release_extension',
  'release_pos_x','release_pos_y','release_pos_z','arm_angle',
  // 직접 누수 — 공기역학 추적
  'pfx_x','pfx_z','plate_x','plate_z',
  'vx0','vy0','vz0','ax','ay','az',
  'effective_speed','api_break_z_with_gravity',
  'api_break_x_arm','api_break_x_batter_in',
  // 직접 누수 — 회전 특성
  'spin_axis','spin_dir','hyper_speed',
  'spin_rate_deprecated','break_angle_deprecated','break_length_deprecated',
  // 결과 누수 — 타격 운동학
  'bat_speed','swing_length','attack_angle','attack_direction','swing_path_tilt',
  'intercept_ball_minus_batter_pos_x_inches','intercept_ball_minus_batter_pos_y_inches',
  // 결과 누수 — 타구 운동학
  'launch_speed','launch_angle','launch_speed_angle',
  'hit_distance_sc','hc_x','hc_y',
  // 결과 누수 — 기대 성적
  'estimated_ba_using_speedangle','estimated_woba_using_speedangle','estimated_slg_using_speedangle',
  // 결과 누수 — Win Expectancy / 사후 스코어
  'delta_home_win_exp','delta_run_exp','delta_pitcher_run_exp',
  'post_away_score','post_home_score','post_bat_score','post_fld_score',
  // 결과 누수 — 결과 통계 및 사후 라벨
  'woba_value','woba_denom','babip_value','iso_value','zone','hit_location',
  // 검토 추가 드롭
  'age_pit_legacy','pitcher_days_until_next_game','batter_days_until_next_game'
]);

// ② INT 컬럼 목록
const INT_COLS = new Set([
  'game_pk','at_bat_number','pitch_number','batter','pitcher','fielder_2',
  'balls','strikes','outs_when_up','inning','on_1b','on_2b','on_3b','game_year'
]);

// ③ CSV 파싱
const lines   = csvText.trim().split('\n');
const headers = lines[0].split(',').map(h => h.replace(/^"|"$/g, '').trim());
const allowedHeaders = headers.filter(h => !LEAKAGE.has(h));

const results = [];
let   invalidPKs = 0;

for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;

  // CSV 값 파싱 (간단 구현: 쉼표로 분리)
  const values = lines[i].split(',').map(v => v.replace(/^"|"$/g, '').trim());
  const row    = {};

  for (let j = 0; j < headers.length; j++) {
    const col = headers[j];
    if (LEAKAGE.has(col)) continue;

    let val = values[j] ?? null;
    if (val === '' || val === 'null' || val === 'NA' || val === 'NaN') val = null;

    // ④ 타입 정규화
    if (val !== null) {
      if (INT_COLS.has(col)) {
        const parsed = parseInt(val, 10);
        val = isNaN(parsed) ? null : parsed;
      } else if (!isNaN(val)) {
        const parsed = parseFloat(val);
        val = isNaN(parsed) ? null : parsed;
      }
    }
    row[col] = val;
  }

  // ⑤ 복합키 검증: (game_pk, at_bat_number, pitch_number)
  if (!row.game_pk || row.at_bat_number == null || !row.pitch_number) {
    invalidPKs++;
    continue;
  }

  results.push(row);
}

console.log(`정제 완료: ${results.length}행 | 누수 드롭: ${LEAKAGE.size}개 | PK 실패: ${invalidPKs}건`);

// one item per row → Node 4(Supabase upsert)가 행별로 처리
// 프로덕션 권장: SplitInBatches 노드(1000행 단위) → Node 4 추가
return results.map(row => ({ json: row }));

// prediction_log 미연결 상태 — 드리프트 감지 스킵
const today = new Date(Date.now() - 86400000).toISOString().split('T')[0];

return [{
  json: {
    date:                today,
    total_predictions:   0,
    correct_predictions: 0,
    accuracy:            0,
    accuracy_pct:        "N/A (prediction_log 미연결)",
    worst_pitch_type:    "N/A",
    worst_pitch_acc:     0,
    pitch_type_stats:    {},
    drift_detected:      false,
    drift_threshold:     0.40
  }
}];

